import React, { useEffect, useState } from "react";
import {
    Layout,
    Card,
    Row,
    Col,
    Button,
    Tag,
    Typography,
    Space,
    Tooltip,
    Divider,
} from "antd";

import {
    AudioMutedOutlined,
    AudioOutlined,
    VideoCameraOutlined,
    VideoCameraAddOutlined,
    LogoutOutlined,
    CheckCircleOutlined,
    LoadingOutlined,
    CloseCircleOutlined,
} from "@ant-design/icons";

import { useWebRTC } from "../hooks/useWebRTC";

const { Header, Content } = Layout;
const { Title, Text } = Typography;

export default function Meeting({ roomId, isInitiator, onLeave }) {
    const {
        localVideo,
        remoteVideo,
        status,
        participants,
        start,
        toggleMute,
        toggleVideo,
        leave,
    } = useWebRTC(roomId);

    const [muted, setMuted] = useState(false);
    const [videoOff, setVideoOff] = useState(false);

    const isMobile = window.innerWidth < 768;

    useEffect(() => {
        start(isInitiator);
    }, []);

    const handleMute = () => {
        toggleMute();
        setMuted((m) => !m);
    };

    const handleVideo = () => {
        toggleVideo();
        setVideoOff((v) => !v);
    };

    const handleLeave = () => {
        leave();
        onLeave();
    };

    const getStatusTag = () => {
        switch (status) {
            case "connected":
                return (
                    <Tag color="success" icon={<CheckCircleOutlined />}>
                        Connected
                    </Tag>
                );

            case "connecting":
                return (
                    <Tag color="processing" icon={<LoadingOutlined />}>
                        Connecting
                    </Tag>
                );

            default:
                return (
                    <Tag color="error" icon={<CloseCircleOutlined />}>
                        Disconnected
                    </Tag>
                );
        }
    };

    return (
        <Layout
            style={{
                minHeight: "100vh",

                background:
                    "linear-gradient(135deg, #020617, #0f172a, #111827)",

                padding: isMobile ? "10px" : "20px",
            }}
        >
            <Header
                style={{
                    background: "rgba(17,24,39,0.65)",

                    backdropFilter: "blur(18px)",

                    border: "1px solid rgba(255,255,255,0.08)",

                    boxShadow: "0 8px 32px rgba(0,0,0,0.35)",

                    borderRadius: "18px",

                    marginBottom: "20px",

                    padding: isMobile ? "16px" : "0 24px",

                    display: "flex",

                    flexWrap: "wrap",

                    gap: "12px",

                    alignItems: "center",

                    justifyContent: "space-between",

                    height: "auto",
                }}
            >
                <div>
                    <Title
                        level={isMobile ? 4 : 2}
                        className="meeting-title"
                    >
                        Nexus Meet
                    </Title>

                    <Text style={{ color: "#cbd5e1" }}>
                        Room ID: <strong>{roomId}</strong>
                    </Text>
                </div>

                <Space wrap size="middle">
                    {getStatusTag()}

                    <Tag color="blue">
                        {participants} Participant
                        {participants !== 1 ? "s" : ""}
                    </Tag>
                </Space>
            </Header>

            <Content>
                <Row gutter={[20, 20]}>
                    <Col xs={24} lg={12}>
                        <Card
                            title="Your Video"
                            bordered={false}
                            style={{
                                borderRadius: "18px",

                                background: "rgba(17,24,39,0.65)",

                                backdropFilter: "blur(18px)",

                                border: "1px solid rgba(255,255,255,0.08)",

                                boxShadow: "0 8px 32px rgba(0,0,0,0.35)",
                            }}
                            bodyStyle={{ padding: "12px" }}
                        >
                            <video
                                ref={localVideo}
                                autoPlay
                                muted
                                playsInline
                                style={{
                                    width: "100%",

                                    height: isMobile ? "220px" : "420px",

                                    borderRadius: "18px",

                                    background: "#000",

                                    objectFit: "cover",

                                    border:
                                        "1px solid rgba(255,255,255,0.08)",

                                    boxShadow:
                                        "0 10px 30px rgba(0,0,0,0.45)",
                                }}
                            />
                        </Card>
                    </Col>

                    <Col xs={24} lg={12}>
                        <Card
                            title="Remote User"
                            bordered={false}
                            style={{
                                borderRadius: "18px",

                                background: "rgba(17,24,39,0.65)",

                                backdropFilter: "blur(18px)",

                                border: "1px solid rgba(255,255,255,0.08)",

                                boxShadow: "0 8px 32px rgba(0,0,0,0.35)",
                            }}
                            bodyStyle={{ padding: "12px" }}
                        >
                            <video
                                ref={remoteVideo}
                                autoPlay
                                playsInline
                                style={{
                                    width: "100%",

                                    height: isMobile ? "220px" : "420px",

                                    borderRadius: "18px",

                                    background: "#000",

                                    objectFit: "cover",

                                    border:
                                        "1px solid rgba(255,255,255,0.08)",

                                    boxShadow:
                                        "0 10px 30px rgba(0,0,0,0.45)",
                                }}
                            />
                        </Card>
                    </Col>
                </Row>

                <Divider />

                <div className="meeting-controls">
                    <Space
                        wrap
                        size="large"
                        style={{
                            justifyContent: "center",
                        }}
                    >
                        <Tooltip title={muted ? "Unmute" : "Mute"}>
                            <Button
                                type={muted ? "primary" : "default"}
                                danger={muted}
                                shape="circle"
                                size="large"
                                icon={
                                    muted ? (
                                        <AudioMutedOutlined />
                                    ) : (
                                        <AudioOutlined />
                                    )
                                }
                                onClick={handleMute}
                                style={{
                                    width: "60px",
                                    height: "60px",
                                }}
                            />
                        </Tooltip>

                        <Tooltip
                            title={
                                videoOff
                                    ? "Enable Video"
                                    : "Disable Video"
                            }
                        >
                            <Button
                                type={videoOff ? "primary" : "default"}
                                danger={videoOff}
                                shape="circle"
                                size="large"
                                icon={
                                    videoOff ? (
                                        <VideoCameraAddOutlined />
                                    ) : (
                                        <VideoCameraOutlined />
                                    )
                                }
                                onClick={handleVideo}
                                style={{
                                    width: "60px",
                                    height: "60px",
                                }}
                            />
                        </Tooltip>

                        <Tooltip title="Leave Meeting">
                            <Button
                                danger
                                type="primary"
                                shape="round"
                                size="large"
                                icon={<LogoutOutlined />}
                                onClick={handleLeave}
                            >
                                Leave Meeting
                            </Button>
                        </Tooltip>
                    </Space>
                </div>
            </Content>
        </Layout>
    );
}