import React, { useState } from "react";
import { useEffect } from "react";

import {
    Input,
    Button,
    message,
    Tag
} from "antd";

import {
    VideoCameraOutlined,
    // UserOutlined,
    CopyOutlined,
    ThunderboltOutlined
} from "@ant-design/icons";



export default function Lobby({ onJoin }) {

    const [inputId, setInputId] = useState("");
    // const [username, setUsername] = useState("");

    const handleCreate = () => {
        const id = Math.random().toString(36).substring(2, 8);

        navigator.clipboard.writeText(id);

        // message.success("Room ID copied");

        onJoin(id, true);
    };

    const handleJoin = () => {
        if (!inputId.trim()) {
            message.error("Enter Room ID");
            return;
        }

        onJoin(inputId.trim(), false);
    };


    useEffect(() => {

        const moveLight = (e) => {

            document.documentElement.style.setProperty(
                "--x",
                `${e.clientX}px`
            );

            document.documentElement.style.setProperty(
                "--y",
                `${e.clientY}px`
            );
        };

        window.addEventListener("mousemove", moveLight);

        return () => {
            window.removeEventListener("mousemove", moveLight);
        };

    }, []);

    return (
        <div
            className="
      relative
      flex
      min-h-screen
      items-center
      justify-center
      overflow-hidden
      bg-[#050816]
    "
        >

            {/* Animated Aurora Background */}

            <div
                className="
        absolute
        inset-0
        opacity-40
        blur-3xl
        animate-pulse
      "
            >
                <div
                    className="
          absolute
          left-[10%]
          top-[20%]
          h-[300px]
          w-[300px]
          rounded-full
          bg-cyan-500
        "
                />

                <div
                    className="
          absolute
          right-[10%]
          top-[10%]
          h-[350px]
          w-[350px]
          rounded-full
          bg-fuchsia-500
        "
                />

                <div
                    className="
          absolute
          bottom-[10%]
          left-[40%]
          h-[250px]
          w-[250px]
          rounded-full
          bg-blue-500
        "
                />
            </div>

            {/* Neon Waves */}

            <div
                className="
        absolute
        bottom-[-20%]
        left-[-30%]
        h-[600px]
        w-[160%]
        rotate-[-8deg]
        opacity-20
        blur-2xl
      "
                style={{
                    background:
                        "repeating-radial-gradient(circle at center, #00bfff 0px, #ff00ff 4px, transparent 10px, transparent 30px)"
                }}
            />

            {/* Cursor Glow */}

            <div
                className="
        pointer-events-none
        absolute
        h-[350px]
        w-[350px]
        rounded-full
        bg-gradient-to-r
        from-cyan-500/20
        via-fuchsia-500/20
        to-blue-500/20
        blur-3xl
        transition-all
        duration-75
      "
                style={{
                    left: "var(--x)",
                    top: "var(--y)",
                    transform: "translate(-50%, -50%)"
                }}
            />

            {/* Glass Card */}

            <div
                className="
        relative
        z-10
        w-[420px]
        rounded-[32px]
        border
        border-white/10
        bg-white/5
        p-10
        shadow-[0_0_80px_rgba(0,183,255,0.12)]
        backdrop-blur-2xl
        transition-all
        duration-300
        hover:scale-[1.02]
        hover:shadow-[0_0_120px_rgba(255,0,212,0.25)]
      "
            >

                {/* Header */}

                <div className="text-center">

                    <div
                        className="
            mx-auto
            flex
            h-20
            w-20
            items-center
            justify-center
            rounded-full
            bg-gradient-to-r
            from-cyan-500
            to-fuchsia-500
            shadow-[0_0_40px_rgba(0,183,255,0.45)]
          "
                    >
                        <VideoCameraOutlined className="text-4xl text-white" />
                    </div>

                    <h1
                        className="
            mt-6
            bg-gradient-to-r
            from-cyan-400
            via-fuchsia-500
            to-blue-500
            bg-clip-text
            text-5xl
            font-extrabold
            text-transparent
          "
                    >
                        Nexus Meet
                    </h1>

                    <p className="mt-3 text-gray-300">
                        Futuristic AI Meeting Experience
                    </p>

                    <div className="mt-5">
                        <Tag color="blue">
                            <ThunderboltOutlined />
                            Fast Connection
                        </Tag>
                    </div>

                </div>

                {/* Buttons */}

                <div className="mt-8 flex flex-col gap-5">

                    <Button
                        type="primary"
                        size="large"
                        block
                        icon={<VideoCameraOutlined />}
                        onClick={handleCreate}
                        className="
            !h-14
            !rounded-2xl
            !border-0
            !bg-gradient-to-r
            from-cyan-500
            to-fuchsia-500
            !font-semibold
            transition-all
            hover:scale-[1.02]
          "
                    >
                        Create Meeting
                    </Button>

                    <div className="text-center text-sm text-gray-400">
                        OR
                    </div>

                    <Input
                        size="large"
                        placeholder="Enter Room ID"
                        value={inputId}
                        onChange={(e) => setInputId(e.target.value)}
                        onKeyDown={(e) =>
                            e.key === "Enter" && handleJoin()
                        }
                        className="
            !h-14
            !rounded-2xl
            !border-white/10
            !bg-white/5
            !text-white
          "
                    />

                    <Button
                        size="large"
                        block
                        icon={<CopyOutlined />}
                        onClick={handleJoin}
                        disabled={!inputId}
                        className="
            !h-14
            !rounded-2xl
            !border-white/10
            !bg-white/5
            !text-white
            transition-all
            hover:!border-cyan-400
            hover:!text-cyan-300
          "
                    >
                        Join Meeting
                    </Button>

                </div>

            </div>

        </div>
    );
}